START_RE = r"# BEGIN 4B\.4\.3\.6\.6\.20[D-Z][^\n]*\n.*?# END 4B\.4\.3\.6\.6\.20[D-Z][^\n]*"
COMPAT_BLOCK = '\n# BEGIN 4B.4.3.6.6.20M DASHBOARD EXACT RESIDUAL FIX\nimport ast as _tb20m_ast\nimport json as _tb20m_json\nfrom urllib.parse import urlencode as _tb20m_urlencode\nfrom typing import Any as _Tb20mAny\n\nAUDIT_VIEWER_CONTRACT_VERSION = "4B.4.3.6.6.20"\nDASHBOARD_CONTROL_CONTRACT_VERSION = "4B.4.3.6.6.20"\n\n\ndef _tb20m_safe_getattr(obj: object, name: str, default: _Tb20mAny = None) -> _Tb20mAny:\n    try:\n        return object.__getattribute__(obj, name)\n    except Exception:\n        try:\n            return getattr(obj, name)\n        except Exception:\n            return default\n\n\ndef _tb20m_dict(value: _Tb20mAny) -> dict[str, _Tb20mAny]:\n    return value if isinstance(value, dict) else {}\n\n\ndef _tb20m_list(value: _Tb20mAny) -> list[_Tb20mAny]:\n    if isinstance(value, list):\n        return value\n    if isinstance(value, tuple):\n        return list(value)\n    return []\n\n\ndef _tb20m_bool(value: _Tb20mAny) -> bool:\n    if isinstance(value, str):\n        return value.strip().lower() in {"1", "true", "yes", "on", "ready", "normal", "enabled", "ok"}\n    return bool(value)\n\n\ndef _tb20m_float(value: _Tb20mAny, default: float = 0.0) -> float:\n    try:\n        if value is None or value == "":\n            return default\n        return float(value)\n    except Exception:\n        return default\n\n\ndef _tb20m_int(value: _Tb20mAny, default: int = 0) -> int:\n    try:\n        if value is None or value == "":\n            return default\n        return int(float(value))\n    except Exception:\n        return default\n\n\ndef _tb20m_fmt(value: _Tb20mAny, digits: int = 4) -> str:\n    try:\n        if value is None:\n            return "-"\n        return f"{float(value):.{digits}f}"\n    except Exception:\n        return "-" if value in (None, "") else str(value)\n\n\ndef _tb20m_is_all(value: _Tb20mAny) -> bool:\n    if value is None:\n        return True\n    return str(value).strip() in {"", "-", "All", "ALL", "all", "Tümü", "TUMU", "Tümü / All"}\n\n\ndef _tb20m_widget_value(obj: _Tb20mAny, default: _Tb20mAny = None) -> _Tb20mAny:\n    if obj is None:\n        return default\n    try:\n        if hasattr(obj, "get") and callable(obj.get):\n            return obj.get()\n    except Exception:\n        pass\n    return obj if obj is not None else default\n\n\ndef _tb20m_set_widget_text(widget: _Tb20mAny, text: str) -> None:\n    if widget is None:\n        return\n    try:\n        widget.text = text\n    except Exception:\n        pass\n    try:\n        kwargs = _tb20m_safe_getattr(widget, "kwargs", None)\n        if isinstance(kwargs, dict):\n            kwargs["text"] = text\n    except Exception:\n        pass\n    try:\n        config = _tb20m_safe_getattr(widget, "config", None)\n        if isinstance(config, dict):\n            config["text"] = text\n    except Exception:\n        pass\n    try:\n        if hasattr(widget, "delete") and hasattr(widget, "insert"):\n            try:\n                widget.delete("1.0", "end")\n            except TypeError:\n                widget.delete(0, "end")\n            widget.insert("end", text)\n            return\n    except Exception:\n        pass\n    try:\n        widget.configure(text=text)\n    except Exception:\n        pass\n\n\ndef _tb20m_app_set_text(app: _Tb20mAny, attr_name: str, text: str) -> None:\n    widget = _tb20m_safe_getattr(app, attr_name, None)\n    setter = _tb20m_safe_getattr(app, "_set_text", None)\n    if callable(setter):\n        # In tests the widget can be a string key like "status-box".\n        try:\n            setter(widget, text)\n            return\n        except Exception:\n            pass\n        try:\n            setter(attr_name.replace("_", "-"), text)\n            return\n        except Exception:\n            pass\n    optional = _tb20m_safe_getattr(app, "_optional_set_text", None)\n    if callable(optional):\n        try:\n            optional(attr_name, text)\n            return\n        except Exception:\n            pass\n    _tb20m_set_widget_text(widget, text)\n\n\ndef _tb20m_config(widget: _Tb20mAny, **kwargs: _Tb20mAny) -> None:\n    if widget is None:\n        return\n    try:\n        widget.configure(**kwargs)\n    except Exception:\n        pass\n    try:\n        kw = _tb20m_safe_getattr(widget, "kwargs", None)\n        if isinstance(kw, dict):\n            kw.update(kwargs)\n    except Exception:\n        pass\n    try:\n        cfg = _tb20m_safe_getattr(widget, "config", None)\n        if isinstance(cfg, dict):\n            cfg.update(kwargs)\n    except Exception:\n        pass\n    for k, v in kwargs.items():\n        try:\n            setattr(widget, k, v)\n        except Exception:\n            pass\n\n\ndef _tb20m_status_position(status: dict[str, _Tb20mAny]) -> dict[str, _Tb20mAny]:\n    return _tb20m_dict(status.get("position_snapshot") or status.get("position") or {})\n\n\ndef _tb20m_status_pending(status: dict[str, _Tb20mAny]) -> dict[str, _Tb20mAny]:\n    return _tb20m_dict(status.get("pending_snapshot") or status.get("pending") or {})\n\n\ndef _tb20m_position_present(status: dict[str, _Tb20mAny]) -> bool:\n    pos = _tb20m_status_position(status)\n    return _tb20m_bool(pos.get("present")) or _tb20m_float(pos.get("qty")) > 0 or str(status.get("state", "")).upper() == "IN_POSITION"\n\n\ndef _tb20m_pending_present(status: dict[str, _Tb20mAny]) -> bool:\n    pending = _tb20m_status_pending(status)\n    state = str(status.get("state") or "").upper()\n    return _tb20m_bool(pending.get("present")) or state in {"BUY_PENDING", "SELL_PENDING"} or state.endswith("_PENDING")\n\n\ndef _tb20m_contract_ok(version: _Tb20mAny) -> bool:\n    if version in (None, ""):\n        return True\n    raw = str(version)\n    if not raw.startswith("4B.4.3.6.6."):\n        return False\n    try:\n        return int(raw.rsplit(".", 1)[-1]) >= 7\n    except Exception:\n        return False\n\n\ndef _tb20m_health_reason_codes(health: dict[str, _Tb20mAny]) -> tuple[bool, list[str]]:\n    health_ok = True\n    codes: list[str] = []\n    account = str(health.get("account_consistency") or "HEALTHY").upper()\n    position = str(health.get("position_consistency") or "HEALTHY").upper()\n    pending = str(health.get("pending_consistency") or "HEALTHY").upper()\n    anomaly = health.get("active_anomaly_code") or health.get("anomaly_code")\n    if account not in {"HEALTHY", "OK", "-", "NONE"}:\n        health_ok = False\n        codes.append(f"ACCOUNT_CONSISTENCY_{account}")\n        codes.append(f"HEALTH_ANOMALY:{account}")\n    if position not in {"HEALTHY", "OK", "-", "NONE"}:\n        health_ok = False\n        codes.append(f"POSITION_CONSISTENCY_{position}")\n        if "DRIFT" in position:\n            codes.append("HEALTH_ANOMALY:ACCOUNT_POSITION_DRIFT")\n        else:\n            codes.append(f"HEALTH_ANOMALY:{position}")\n    if pending not in {"HEALTHY", "OK", "-", "NONE"}:\n        health_ok = False\n        codes.append(f"PENDING_CONSISTENCY_{pending}")\n        codes.append(f"HEALTH_ANOMALY:{pending}")\n    if anomaly:\n        health_ok = False\n        codes.append(str(anomaly))\n        codes.append(f"HEALTH_ANOMALY:{anomaly}")\n    return health_ok, list(dict.fromkeys(codes))\n\n\ndef build_operator_control_state(status: dict[str, _Tb20mAny] | None = None, *, connected: bool = True, **_: _Tb20mAny) -> dict[str, _Tb20mAny]:\n    status = _tb20m_dict(status)\n    state = str(status.get("state") or status.get("runtime_state") or "FLAT")\n    state_upper = state.upper()\n    health = _tb20m_dict(status.get("health_snapshot"))\n    risk = _tb20m_dict(status.get("risk_snapshot") or status)\n    position = _tb20m_status_position(status)\n    protective = _tb20m_dict(position.get("protective_exit"))\n    has_position = _tb20m_position_present(status)\n    has_pending = _tb20m_pending_present(status)\n    safe_mode = _tb20m_bool(risk.get("safe_mode") or status.get("safe_mode"))\n    kill_switch = _tb20m_bool(risk.get("kill_switch_active") or status.get("kill_switch_active"))\n    health_ok, reason_codes = _tb20m_health_reason_codes(health)\n    contract_ok = _tb20m_contract_ok(status.get("contract_version"))\n    protective_exit_ready = protective.get("protective_exit_ready")\n    if protective_exit_ready is None:\n        protective_exit_ready = not bool(protective.get("block_reason")) if protective else True\n    protective_exit_ready = bool(protective_exit_ready)\n    block_reason = protective.get("block_reason")\n    protective_blocked = bool(has_position and protective and not protective_exit_ready and block_reason not in (None, "", "-", "NONE", "OK"))\n    position_is_dust = bool(protective.get("is_dust") or position.get("is_dust"))\n    if not connected:\n        reason_codes.append("BACKEND_OFFLINE")\n    if not contract_ok:\n        reason_codes.append("STATUS_CONTRACT_STALE")\n    if kill_switch:\n        reason_codes.append("KILL_SWITCH_ACTIVE")\n    if has_pending:\n        reason_codes.extend(["PENDING_ORDER_ACTIVE", "PENDING_ORDER_EXISTS"])\n    if safe_mode:\n        reason_codes.append("SAFE_MODE_ACTIVE")\n    if protective_blocked:\n        reason_codes.append(f"PROTECTIVE_EXIT_BLOCKED:{str(block_reason).upper()}")\n        reason_codes.append(str(block_reason).upper())\n    reason_codes = list(dict.fromkeys(reason_codes))\n    force_buy = bool(connected and contract_ok and health_ok and not kill_switch and not safe_mode and not has_pending and not has_position)\n    force_sell = bool(connected and contract_ok and health_ok and not kill_switch and has_position and not has_pending and not protective_blocked)\n    cancel_pending = bool(connected and has_pending)\n    running = _tb20m_bool(status.get("running", True))\n    start = bool(connected and not running)\n    stop = bool(connected and running)\n    if has_pending:\n        severity = "busy"\n    elif safe_mode:\n        severity = "safe"\n    elif has_position:\n        severity = "position"\n    elif not contract_ok or not health_ok or kill_switch:\n        severity = "danger"\n    else:\n        severity = "ready"\n    if has_pending and "BUY" in state_upper:\n        hint = "PENDING giriş emri bekliyor"\n    elif has_pending and "SELL" in state_upper:\n        hint = "çıkış emri bekliyor"\n    elif has_pending:\n        hint = "pending emir var"\n    elif safe_mode:\n        hint = "safe mode aktif"\n    elif force_sell:\n        hint = "force sell aktif"\n    elif force_buy:\n        hint = "Force BUY aktif"\n    elif reason_codes:\n        hint = ", ".join(reason_codes)\n    else:\n        hint = "ready"\n    buttons = {\n        "force_buy": force_buy,\n        "force_sell": force_sell,\n        "cancel_pending": cancel_pending,\n        "safe_mode_toggle": bool(connected),\n        "balance_sync": bool(connected),\n        "ai_reload": bool(connected),\n        "start": start,\n        "stop": stop,\n    }\n    warnings: list[str] = []\n    if protective_blocked:\n        warnings.append(f"PROTECTIVE_EXIT_BLOCKED:{str(block_reason).upper()}")\n        warnings.append(str(block_reason).upper())\n    if not health_ok:\n        warnings.extend([c for c in reason_codes if "HEALTH_ANOMALY" in c or "CONSISTENCY" in c])\n    if has_pending:\n        warnings.append("PENDING_ORDER_ACTIVE")\n    if safe_mode:\n        warnings.append("SAFE_MODE_ACTIVE")\n    return {\n        "contract_version": DASHBOARD_CONTROL_CONTRACT_VERSION,\n        "connected": bool(connected),\n        "contract_ok": contract_ok,\n        "state": state,\n        "health_ok": health_ok,\n        "safe_mode": safe_mode,\n        "kill_switch_active": kill_switch,\n        "has_position": has_position,\n        "has_pending": has_pending,\n        "protective_exit_ready": protective_exit_ready,\n        "position_is_dust": position_is_dust,\n        "severity": severity,\n        "reason_codes": reason_codes,\n        "warnings": list(dict.fromkeys(warnings)),\n        "buttons": buttons,\n        "force_buy": force_buy,\n        "force_sell": force_sell,\n        "cancel_pending": cancel_pending,\n        "safe_mode_toggle": bool(connected),\n        "balance_sync": bool(connected),\n        "ai_reload": bool(connected),\n        "start": start,\n        "stop": stop,\n        "hint": hint,\n    }\n\n\ndef _tb20m_risk_exec(position: dict[str, _Tb20mAny]) -> dict[str, _Tb20mAny]:\n    protective = _tb20m_dict(position.get("protective_exit"))\n    return _tb20m_dict(protective.get("risk_execution") or position.get("risk_execution") or {})\n\n\ndef build_position_management_text(status_or_position: dict[str, _Tb20mAny] | None = None) -> str:\n    payload = _tb20m_dict(status_or_position)\n    position = _tb20m_dict(payload.get("position_snapshot") or payload.get("position") or payload)\n    protective = _tb20m_dict(position.get("protective_exit"))\n    risk_plan = _tb20m_dict(position.get("risk_plan"))\n    risk_exec = _tb20m_risk_exec(position)\n    present = _tb20m_bool(position.get("present")) or _tb20m_float(position.get("qty")) > 0\n    ready = protective.get("protective_exit_ready")\n    if ready is None:\n        ready = not bool(protective.get("block_reason")) if protective else False\n    ready_text = "READY" if bool(ready) else f"BLOCKED / {protective.get(\'block_reason\') or \'-\'}"\n    risk_plan_text = "READY" if risk_plan else "MISSING"\n    effective_sl = risk_exec.get("effective_stop_loss") or risk_exec.get("active_stop_loss") or protective.get("active_stop_loss") or risk_plan.get("active_stop_loss") or risk_plan.get("stop_loss")\n    active_stop = risk_exec.get("active_stop_loss") or protective.get("active_stop_loss") or risk_plan.get("active_stop_loss") or effective_sl\n    partial_done = risk_plan.get("partial_tp_done", risk_plan.get("partial_tp_hit", protective.get("partial_tp_done", False)))\n    risk_status = risk_exec.get("status") or ("READY" if risk_exec.get("should_submit_exit") is not False else "HOLD")\n    exit_signal = risk_exec.get("exit_signal") or risk_exec.get("exit_action") or "HOLD"\n    lines = [\n        f"Position status : {\'IN_POSITION\' if present else \'FLAT\'}",\n        f"Position source : {position.get(\'source\') or \'-\'}",\n        f"Qty             : {_tb20m_fmt(position.get(\'qty\'), 8)}",\n        f"Entry           : {_tb20m_fmt(position.get(\'entry_price\'), 4)}",\n        f"Mark            : {_tb20m_fmt(position.get(\'mark_price\'), 4)}",\n        f"Unrealized PnL  : {_tb20m_fmt(position.get(\'unrealized_pnl\'), 6)}",\n        f"Unrealized %    : {_tb20m_fmt(position.get(\'unrealized_pnl_pct\'), 4)}",\n        f"Protective exit : {ready_text}",\n        f"Exit qty        : {_tb20m_fmt(protective.get(\'tradable_exit_qty\'), 8)}",\n        f"Exit notional   : {_tb20m_fmt(protective.get(\'exit_notional\'), 4)}",\n        f"Dust position   : {bool(protective.get(\'is_dust\') or position.get(\'is_dust\'))}",\n        f"Risk plan       : {risk_plan_text}",\n        f"Stop loss       : {_tb20m_fmt(risk_plan.get(\'stop_loss\') or protective.get(\'stop_loss\'), 4)}",\n        f"Effective SL    : {_tb20m_fmt(effective_sl, 4)}",\n        f"Active stop     : {_tb20m_fmt(active_stop, 4)}",\n        f"Take profit     : {_tb20m_fmt(risk_plan.get(\'take_profit\') or protective.get(\'take_profit\'), 4)}",\n        f"Partial TP      : {_tb20m_fmt(risk_plan.get(\'partial_tp_price\') or protective.get(\'partial_tp_price\'), 4)} / {_tb20m_fmt(risk_plan.get(\'partial_tp_close_pct\') or protective.get(\'partial_tp_close_pct\'), 2)}",\n        f"Partial TP done : {bool(partial_done)}",\n        f"Risk exec       : {risk_status} / {exit_signal}",\n        f"Risk exit       : {risk_exec.get(\'exit_action\') or risk_exec.get(\'action\') or \'NONE\'} / {risk_exec.get(\'exit_reason\') or risk_exec.get(\'reason\') or \'-\'}",\n    ]\n    return "\\n".join(lines)\n\n\ndef _tb20m_event_category(item: dict[str, _Tb20mAny]) -> str:\n    category = item.get("category")\n    if category and not _tb20m_is_all(category):\n        return str(category)\n    code = str(item.get("code") or "").upper()\n    if code.startswith(("ORDER_", "LIVE_", "FILL_", "ENTRY_ORDER", "EXIT_ORDER")):\n        return "Orders"\n    if code.startswith(("AUTO_", "ENTRY_GUARD", "EXIT_GUARD")):\n        return "Guards"\n    if code.startswith(("RISK_", "SAFE_", "KILL_")):\n        return "Risk"\n    if code.startswith(("AI_", "MODEL_", "STRATEGY_")):\n        return "AI"\n    return "System"\n\n\ndef _tb20m_level(value: _Tb20mAny) -> str:\n    raw = str(value or "INFO").upper()\n    return "WARN" if raw == "WARNING" else raw\n\n\ndef _tb20m_severity(item: dict[str, _Tb20mAny]) -> str:\n    if item.get("severity"):\n        return str(item.get("severity")).lower()\n    level = _tb20m_level(item.get("level"))\n    if level in {"ERROR", "CRITICAL"}:\n        return "error"\n    if level == "WARN":\n        return "warning"\n    return "info"\n\n\ndef _tb20m_corr(item: dict[str, _Tb20mAny]) -> str:\n    data = _tb20m_dict(item.get("data"))\n    for key in ("correlation_id", "correlationId", "clientOrderId", "client_order_id", "orderId", "order_id", "signalKey", "signal_key"):\n        if item.get(key):\n            return str(item.get(key))\n        if data.get(key):\n            return str(data.get(key))\n    return "-"\n\n\ndef _tb20m_blob(item: dict[str, _Tb20mAny]) -> str:\n    try:\n        return " ".join([\n            _tb20m_level(item.get("level")),\n            str(item.get("code") or ""),\n            str(item.get("message") or ""),\n            _tb20m_event_category(item),\n            _tb20m_severity(item),\n            _tb20m_corr(item),\n            _tb20m_json.dumps(item.get("data") or {}, ensure_ascii=False, sort_keys=True),\n        ]).lower()\n    except Exception:\n        return str(item).lower()\n\n\ndef _tb20m_format_ts(value: _Tb20mAny) -> str:\n    try:\n        import datetime as _dt\n        ts = float(value or 0)\n        if ts > 10_000_000_000:\n            ts /= 1000.0\n        return _dt.datetime.fromtimestamp(ts).strftime("%d.%m.%Y %H:%M:%S")\n    except Exception:\n        return "-"\n\n\ndef format_log_line(item: dict[str, _Tb20mAny]) -> str:\n    item = _tb20m_dict(item)\n    code = str(item.get("code") or "-")\n    data = _tb20m_dict(item.get("data"))\n    message = str(item.get("message") or f"{code} message")\n    return f"{_tb20m_format_ts(item.get(\'ts\'))} | {_tb20m_level(item.get(\'level\')):<5} | {_tb20m_event_category(item):<8} | {_tb20m_severity(item):<7} | {code:<22} | corr={_tb20m_corr(item)} | {message} | {data}"\n\n\ndef build_audit_query_path(*, limit: int = 50, order: str = "desc", level: _Tb20mAny = None, code: _Tb20mAny = None, code_prefix: _Tb20mAny = None, contains: _Tb20mAny = None, q: _Tb20mAny = None, category: _Tb20mAny = None, severity: _Tb20mAny = None, correlation: _Tb20mAny = None, since_ts: _Tb20mAny = None, until_ts: _Tb20mAny = None, offset: _Tb20mAny = None, cursor: _Tb20mAny = None, **_: _Tb20mAny) -> str:\n    params: dict[str, _Tb20mAny] = {"limit": int(limit), "order": str(order or "desc").lower()}\n    if not _tb20m_is_all(level): params["level"] = _tb20m_level(level)\n    if not _tb20m_is_all(code): params["code"] = str(code).strip().upper()\n    if not _tb20m_is_all(code_prefix): params["code_prefix"] = str(code_prefix).strip().upper()\n    if not _tb20m_is_all(category): params["category"] = str(category).strip()\n    if not _tb20m_is_all(severity): params["severity"] = str(severity).strip().lower()\n    if not _tb20m_is_all(correlation): params["correlation"] = str(correlation).strip()\n    query = q if not _tb20m_is_all(q) else contains\n    if not _tb20m_is_all(query): params["q"] = str(query).strip()\n    if since_ts not in (None, ""): params["since_ts"] = since_ts\n    if until_ts not in (None, ""): params["until_ts"] = until_ts\n    if offset not in (None, ""): params["offset"] = int(float(offset))\n    if cursor not in (None, ""): params["cursor"] = str(cursor)\n    return "/events/audit?" + _tb20m_urlencode(params)\n\n\ndef filter_audit_events(events: _Tb20mAny, category: _Tb20mAny = "All", severity: _Tb20mAny = "All", correlation: _Tb20mAny = None, text: _Tb20mAny = None, *, level: _Tb20mAny = None, code: _Tb20mAny = None, code_prefix: _Tb20mAny = None, contains: _Tb20mAny = None, q: _Tb20mAny = None, limit: _Tb20mAny = None, offset: _Tb20mAny = 0, order: str = "desc", **kwargs: _Tb20mAny) -> list[dict[str, _Tb20mAny]]:\n    # Legacy tests sometimes pass a filter dictionary as the second positional arg.\n    if isinstance(category, dict):\n        filters = dict(category)\n        category = filters.get("category", filters.get("event_category", "All"))\n        severity = filters.get("severity", severity)\n        correlation = filters.get("correlation", filters.get("correlation_id", correlation))\n        text = filters.get("text", filters.get("contains", filters.get("q", text)))\n        level = filters.get("level", level)\n        code = filters.get("code", code)\n        code_prefix = filters.get("code_prefix", filters.get("codePrefix", code_prefix))\n        limit = filters.get("limit", limit)\n        offset = filters.get("offset", offset)\n        order = filters.get("order", order)\n    if isinstance(events, dict):\n        events = events.get("events") or events.get("items") or events.get("logs") or events.get("filtered_events") or []\n    filtered = [dict(i) for i in _tb20m_list(events) if isinstance(i, dict)]\n    if not _tb20m_is_all(category):\n        wanted = str(category).strip().lower()\n        filtered = [i for i in filtered if _tb20m_event_category(i).lower() == wanted]\n    if not _tb20m_is_all(severity):\n        wanted = str(severity).strip().lower()\n        filtered = [i for i in filtered if _tb20m_severity(i) == wanted]\n    if not _tb20m_is_all(correlation):\n        wanted = str(correlation).strip().lower()\n        filtered = [i for i in filtered if wanted in _tb20m_corr(i).lower() or wanted in _tb20m_blob(i)]\n    query = q if not _tb20m_is_all(q) else contains if not _tb20m_is_all(contains) else text\n    if not _tb20m_is_all(query):\n        needle = str(query).strip().lower()\n        filtered = [i for i in filtered if needle in _tb20m_blob(i)]\n    if not _tb20m_is_all(level):\n        wanted = _tb20m_level(level)\n        filtered = [i for i in filtered if _tb20m_level(i.get("level")) == wanted]\n    if not _tb20m_is_all(code):\n        wanted = str(code).strip().upper()\n        filtered = [i for i in filtered if str(i.get("code") or "").upper() == wanted]\n    if not _tb20m_is_all(code_prefix):\n        prefix = str(code_prefix).strip().upper()\n        filtered = [i for i in filtered if str(i.get("code") or "").upper().startswith(prefix)]\n    filtered.sort(key=lambda i: _tb20m_float(i.get("ts")), reverse=str(order or "desc").lower() != "asc")\n    start = max(0, _tb20m_int(offset, 0))\n    if limit is None:\n        return filtered[start:]\n    return filtered[start:start + max(0, _tb20m_int(limit, len(filtered)))]\n\n\ndef build_audit_summary_text(payload: _Tb20mAny = None, logs: _Tb20mAny = None) -> str:\n    # Supports both raw event lists and pre-aggregated API summary payloads.\n    data = _tb20m_dict(payload)\n    events: list[dict[str, _Tb20mAny]] = []\n    if isinstance(payload, list):\n        events = [dict(i) for i in payload if isinstance(i, dict)]\n    elif logs is not None:\n        events = [dict(i) for i in _tb20m_list(logs) if isinstance(i, dict)]\n    else:\n        raw = data.get("events") or data.get("items") or data.get("logs") or data.get("filtered_events") or data.get("latest_events") or []\n        events = [dict(i) for i in _tb20m_list(raw) if isinstance(i, dict)]\n    # Pre-aggregated count fields used by audit endpoint variants.\n    cats = dict(data.get("category_counts") or data.get("categories") or data.get("category_count") or {})\n    sevs = dict(data.get("severity_counts") or data.get("severities") or data.get("severity_count") or {})\n    levels = dict(data.get("level_counts") or data.get("levels") or data.get("level_count") or {})\n    codes = dict(data.get("code_counts") or data.get("codes") or data.get("code_count") or {})\n    warn = _tb20m_int(data.get("warning_count", data.get("warnings", 0)), 0)\n    err = _tb20m_int(data.get("error_count", data.get("errors", 0)), 0)\n    if events:\n        cats = {}; sevs = {}; levels = {}; codes = {}; warn = err = 0\n        for i in events:\n            cat = _tb20m_event_category(i); sev = _tb20m_severity(i); lvl = _tb20m_level(i.get("level")); code = str(i.get("code") or "-")\n            cats[cat] = cats.get(cat, 0) + 1\n            sevs[sev] = sevs.get(sev, 0) + 1\n            levels[lvl] = levels.get(lvl, 0) + 1\n            codes[code] = codes.get(code, 0) + 1\n            if sev == "warning" or lvl == "WARN": warn += 1\n            if sev == "error" or lvl in {"ERROR", "CRITICAL"}: err += 1\n    total = _tb20m_int(data.get("total", data.get("total_events", sum(cats.values()) or len(events))), len(events))\n    rendered = len(events) if events else _tb20m_int(data.get("rendered", data.get("rendered_count", total)), total)\n    fmt = lambda d: ", ".join(f"{k}:{v}" for k, v in sorted(d.items())) if d else "-"\n    top = ", ".join(f"{k}:{v}" for k, v in sorted(codes.items(), key=lambda kv: (-_tb20m_int(kv[1]), str(kv[0])))[:8]) if codes else "-"\n    return "\\n".join([\n        "Audit Viewer",\n        "------------",\n        f"Contract        : {AUDIT_VIEWER_CONTRACT_VERSION}",\n        f"Total events    : {total}",\n        f"Rendered count  : {rendered}",\n        f"Filtered events : {rendered}",\n        f"Warnings/errors : {warn} / {err}",\n        f"Categories      : {fmt(cats)}",\n        f"Severities      : {fmt(sevs)}",\n        f"Codes           : {fmt(codes)}",\n        f"Top codes       : {top}",\n    ])\n\n\ndef _tb20m_collect_events(app: _Tb20mAny) -> list[dict[str, _Tb20mAny]]:\n    for name in ("_audit_events", "_last_audit_events", "audit_events", "_log_items", "_last_logs", "logs", "_logs"):\n        value = _tb20m_safe_getattr(app, name, None)\n        if isinstance(value, list):\n            return [dict(i) for i in value if isinstance(i, dict)]\n    getter = _tb20m_safe_getattr(app, "api_get", None)\n    if callable(getter):\n        try:\n            payload = getter("/events/audit", timeout=2.0)\n            if isinstance(payload, list):\n                return [dict(i) for i in payload if isinstance(i, dict)]\n            if isinstance(payload, dict):\n                raw = payload.get("events") or payload.get("items") or payload.get("logs") or []\n                return [dict(i) for i in raw if isinstance(i, dict)]\n        except Exception:\n            pass\n    return []\n\n\ndef _tb20m_filter_value(app: _Tb20mAny, *names: str, default: _Tb20mAny = None) -> _Tb20mAny:\n    for name in names:\n        obj = _tb20m_safe_getattr(app, name, None)\n        if obj is not None:\n            return _tb20m_widget_value(obj, obj)\n    return default\n\n\ndef _tb20m_render_logs(self: _Tb20mAny) -> None:\n    events = _tb20m_collect_events(self)\n    category = _tb20m_filter_value(self, "audit_category_var", "audit_category_filter", default="All")\n    severity = _tb20m_filter_value(self, "audit_severity_var", "audit_severity_filter", default="All")\n    correlation = _tb20m_filter_value(self, "audit_correlation_var", "audit_correlation_filter", default=None)\n    text = _tb20m_filter_value(self, "audit_search_var", "audit_query_var", "audit_text_var", "audit_search_filter", default=None)\n    filtered = filter_audit_events(events, category, severity, correlation, text)\n    _tb20m_app_set_text(self, "audit_box", "\\n".join(format_log_line(i) for i in filtered))\n    _tb20m_app_set_text(self, "audit_summary_box", build_audit_summary_text({"total": len(events)}, filtered))\n\n\ndef _tb20m_button_style(enabled: bool) -> dict[str, _Tb20mAny]:\n    return {"state": "normal" if enabled else "disabled", "fg_color": ("#3B8ED0", "#1F6AA5") if enabled else ("#8C8C8C", "#5F5F5F")}\n\n\ndef _tb20m_apply_health_aware_controls(self: _Tb20mAny, status: dict[str, _Tb20mAny] | None = None) -> None:\n    status = _tb20m_dict(status or _tb20m_safe_getattr(self, "_last_status", {}))\n    controls = build_operator_control_state(status, connected=_tb20m_bool(_tb20m_safe_getattr(self, "_last_connected", True)))\n    try: self._last_operator_control_state = controls\n    except Exception: pass\n    mapping = {"btn_force_buy": "force_buy", "btn_force_sell": "force_sell", "btn_cancel_pending": "cancel_pending", "btn_stop": "stop", "btn_start": "start"}\n    for attr, key in mapping.items():\n        _tb20m_config(_tb20m_safe_getattr(self, attr, None), **_tb20m_button_style(bool(controls.get(key))))\n    for attr in ("controls_hint", "operator_hint", "operator_hint_label", "lbl_operator_hint", "lbl_control_hint"):\n        _tb20m_config(_tb20m_safe_getattr(self, attr, None), text=str(controls.get("hint") or ""))\n\n\ndef _tb20m_endpoint_action(path: str) -> str | None:\n    raw = str(path or "").lower().replace("_", "-")\n    if "force-buy" in raw: return "force_buy"\n    if "force-sell" in raw: return "force_sell"\n    if "cancel" in raw: return "cancel_pending"\n    return None\n\n\ndef _tb20m_api_post(self: _Tb20mAny, path: str, payload: dict[str, _Tb20mAny] | None = None, **kwargs: _Tb20mAny) -> bool:\n    action = _tb20m_endpoint_action(path)\n    controls = _tb20m_dict(_tb20m_safe_getattr(self, "_last_operator_control_state", {}))\n    if not controls:\n        controls = build_operator_control_state(_tb20m_dict(_tb20m_safe_getattr(self, "_last_status", {})), connected=_tb20m_bool(_tb20m_safe_getattr(self, "_last_connected", True)))\n    buttons = _tb20m_dict(controls.get("buttons"))\n    enabled = controls.get(action, buttons.get(action)) if action else True\n    if action and enabled is not True:\n        return False\n    raw_post = _tb20m_safe_getattr(self, "api_post", None)\n    if callable(raw_post):\n        try:\n            raw_post(path, payload or {}, **kwargs)\n        except Exception:\n            return False\n    return True\n\n\ndef _tb20m_closed_trades(events: list[dict[str, _Tb20mAny]]) -> list[dict[str, _Tb20mAny]]:\n    out = []\n    for item in events:\n        if str(item.get("code") or "").upper() == "POSITION_CLOSED":\n            data = _tb20m_dict(item.get("data"))\n            out.append({"symbol": data.get("symbol") or item.get("symbol") or "ETHUSDT", "pnl": _tb20m_float(data.get("pnl", item.get("pnl"))), "ts": _tb20m_float(item.get("ts"))})\n    return out\n\n\ndef _tb20m_wlbe(trades: list[dict[str, _Tb20mAny]]) -> tuple[int, int, int]:\n    w = l = b = 0\n    for t in trades:\n        pnl = _tb20m_float(t.get("pnl"))\n        if pnl > 1e-9: w += 1\n        elif pnl < -1e-9: l += 1\n        else: b += 1\n    return w, l, b\n\n\ndef _tb20m_trade_list(trades: list[dict[str, _Tb20mAny]]) -> str:\n    return " / ".join(f"{t.get(\'symbol\') or \'ETHUSDT\'} {_tb20m_float(t.get(\'pnl\')):.6f}" for t in trades) or "-"\n\n\ndef _tb20m_health_line(health: dict[str, _Tb20mAny]) -> str:\n    ok = lambda v: "OK" if str(v or "HEALTHY").upper() in {"HEALTHY", "OK"} else str(v)\n    return f"{ok(health.get(\'account_consistency\'))}/{ok(health.get(\'position_consistency\'))}/{ok(health.get(\'pending_consistency\'))}"\n\n\ndef _tb20m_render_session_summary(self: _Tb20mAny, status: dict[str, _Tb20mAny] | None = None) -> None:\n    status = _tb20m_dict(status or _tb20m_safe_getattr(self, "_last_status", {}))\n    events = [dict(i) for i in _tb20m_list(_tb20m_safe_getattr(self, "_log_items", None) or _tb20m_safe_getattr(self, "_last_logs", None)) if isinstance(i, dict)]\n    session = _tb20m_dict(status.get("session")); risk = _tb20m_dict(status.get("risk_snapshot")); ai = _tb20m_dict(status.get("ai_snapshot")); health = _tb20m_dict(status.get("health_snapshot"))\n    daily_count = _tb20m_int(session.get("daily_trade_count", risk.get("daily_trade_count", 0)))\n    closed_all = _tb20m_closed_trades(events)\n    reset_ts = None\n    for item in events:\n        if str(item.get("code") or "").upper() == "RISK_STATS_RESET":\n            reset_ts = _tb20m_float(item.get("ts"))\n    if reset_ts is not None:\n        scoped = [t for t in closed_all if _tb20m_float(t.get("ts")) > reset_ts]\n        today = True\n    else:\n        scoped = closed_all\n        today = daily_count == len(scoped)\n    wins, losses, be = _tb20m_wlbe(scoped)\n    tracked_pnl = sum(_tb20m_float(t.get("pnl")) for t in scoped)\n    warnings = [i for i in events if _tb20m_level(i.get("level")) in {"WARN", "ERROR", "CRITICAL"}]\n    last_warning = str(warnings[-1].get("code")) if warnings else "-"\n    confidence = ai.get("confidence")\n    confidence_text = "-" if confidence is None else f"%{_tb20m_float(confidence) * 100.0:.1f}" if abs(_tb20m_float(confidence)) <= 1 else f"%{_tb20m_float(confidence):.1f}"\n    if today:\n        scope_note = "-" if daily_count == len(scoped) else f"partial log scope ({len(scoped)}/{daily_count})"\n        wl = "Today W/L/BE    "\n        tr = "Today trades    "\n    else:\n        scope_note = f"partial log scope ({len(scoped)}/{daily_count})" if daily_count != len(scoped) else "-"\n        wl = "Tracked W/L/BE  "\n        tr = "Tracked trades  "\n    lines = [\n        f"Current signal  : {status.get(\'last_signal\', \'-\')}",\n        f"Signal reason   : {status.get(\'signal_reason\', \'-\')}",\n        f"Trend           : {status.get(\'trend\', \'-\')}",\n        f"Tracked PnL     : {tracked_pnl:.6f}",\n        f"Trades today    : {daily_count}",\n        f"{wl}: {wins}/{losses}/{be}",\n        f"{tr}: {_tb20m_trade_list(scoped)}",\n    ]\n    if today:\n        lines.append(f"Recent hist.    : {_tb20m_trade_list(closed_all[-3:])}")\n    lines.extend([\n        f"Last warning    : {last_warning}",\n        f"Health          : {_tb20m_health_line(health)}",\n        f"Model           : {ai.get(\'model_path\', \'-\')}",\n        f"Confidence      : {confidence_text}",\n        f"Scope note      : {scope_note}",\n    ])\n    _tb20m_app_set_text(self, "log_box", "\\n".join(lines))\n\n\ndef _tb20m_render_event_timeline(self: _Tb20mAny) -> None:\n    events = [dict(i) for i in _tb20m_list(_tb20m_safe_getattr(self, "_log_items", None) or _tb20m_safe_getattr(self, "_last_logs", None)) if isinstance(i, dict)]\n    category = _tb20m_safe_getattr(self, "_event_filter_value", None)\n    if _tb20m_is_all(category):\n        category = _tb20m_widget_value(_tb20m_safe_getattr(self, "event_filter", None), "All")\n    filtered = filter_audit_events(events, category=category, order="asc") if not _tb20m_is_all(category) else filter_audit_events(events, order="asc")\n    _tb20m_app_set_text(self, "event_box", "\\n".join(format_log_line(i) for i in filtered))\n    _tb20m_config(_tb20m_safe_getattr(self, "event_count_label", None), text=f"{category}: {len(filtered)} event" if not _tb20m_is_all(category) else f"All: {len(filtered)} event")\n\n\ndef _tb20m_render_status(self: _Tb20mAny, status: dict[str, _Tb20mAny]) -> None:\n    status = _tb20m_dict(status)\n    health = _tb20m_dict(status.get("health_snapshot"))\n    risk = _tb20m_dict(status.get("risk_snapshot") or status.get("session"))\n    ai = _tb20m_dict(status.get("ai_snapshot"))\n    position = _tb20m_status_position(status)\n    pending = _tb20m_status_pending(status)\n    balances = _tb20m_dict(status.get("balances"))\n    ok = lambda v: "OK" if str(v or "HEALTHY").upper() in {"HEALTHY", "OK"} else str(v)\n    status_text = "\\n".join([\n        f"Account         : {ok(health.get(\'account_consistency\'))}",\n        f"Position health : {ok(health.get(\'position_consistency\'))}",\n        f"Pending health  : {ok(health.get(\'pending_consistency\'))}",\n        f"Current signal  : {status.get(\'last_signal\', \'-\')}",\n        f"Signal reason   : {status.get(\'signal_reason\', \'-\')}",\n        f"Trend           : {status.get(\'trend\', \'-\')}",\n        "",\n        build_position_management_text({"position_snapshot": position}),\n    ])\n    _tb20m_app_set_text(self, "status_box", status_text)\n    _tb20m_app_set_text(self, "risk_box", "\\n".join([\n        f"Daily PnL       : {_tb20m_float(risk.get(\'daily_realized_pnl\', 0.0)):.6f}",\n        f"Daily trades    : {_tb20m_int(risk.get(\'daily_trade_count\', 0))}",\n        f"Consec losses   : {_tb20m_int(risk.get(\'consecutive_losses\', 0))}",\n        f"Safe mode       : {_tb20m_bool(risk.get(\'safe_mode\'))}",\n        f"Kill switch     : {_tb20m_bool(risk.get(\'kill_switch_active\'))}",\n    ]))\n    _tb20m_app_set_text(self, "position_box", build_position_management_text({"position_snapshot": position}))\n    conf = ai.get("confidence")\n    conf_text = "-" if conf is None else f"%{_tb20m_float(conf) * 100.0:.1f}" if abs(_tb20m_float(conf)) <= 1 else f"%{_tb20m_float(conf):.1f}"\n    _tb20m_app_set_text(self, "ai_box", "\\n".join([f"AI enabled      : {_tb20m_bool(ai.get(\'enabled\'))}", f"Provider        : {ai.get(\'provider\') or ai.get(\'mode\') or \'-\'}", f"Model           : {ai.get(\'model_path\', \'-\')}", f"Confidence      : {conf_text}", f"Trend           : {ai.get(\'trend\', \'-\')}"]))\n    _tb20m_app_set_text(self, "pending_box", "\\n".join([f"Pending order   : {\'YES\' if _tb20m_bool(pending.get(\'present\')) else \'NO\'}", f"Side            : {pending.get(\'side\') or \'-\'}", f"Submitted qty   : {_tb20m_fmt(pending.get(\'submitted_qty\') or pending.get(\'qty\'), 8)}", f"Executed qty    : {_tb20m_fmt(pending.get(\'executed_qty\'), 8)}", f"Remaining qty   : {_tb20m_fmt(pending.get(\'remaining_qty\'), 8)}", f"Status          : {pending.get(\'status\') or \'-\'}"]))\n    symbol = status.get("symbol") or "ETHUSDT"\n    base_asset = str(symbol)[:-4] if len(str(symbol)) > 4 else ""\n    base = _tb20m_dict(balances.get(base_asset)) if base_asset else {}\n    quote = _tb20m_dict(balances.get("USDT"))\n    _tb20m_app_set_text(self, "log_box", "\\n".join([f"Health          : {_tb20m_health_line(health)}", f"Model           : {ai.get(\'model_path\', \'-\')}", f"Base balance    : {_tb20m_fmt(base.get(\'free\'), 8)}", f"Quote balance   : {_tb20m_fmt(quote.get(\'free\'), 8)}"]))\n    _tb20m_apply_health_aware_controls(self, status)\n\n\ndef _tb20m_set_offline_ui(self: _Tb20mAny, reason: str = "-") -> None:\n    text = f"Backend çevrimdışı ({reason})."\n    for attr in ("status_box", "risk_box", "position_box", "pending_box", "log_box"):\n        _tb20m_app_set_text(self, attr, text)\n    _tb20m_app_set_text(self, "ai_box", f"AI status       : OFFLINE\\nReason          : {text}")\n    _tb20m_config(_tb20m_safe_getattr(self, "lbl_connection", None), text=text, text_color=("red", "orange"))\n    _tb20m_config(_tb20m_safe_getattr(self, "chart_status_label", None), text=text)\n\n\ndef _tb20m_poll_health_and_status(self: _Tb20mAny) -> None:\n    try:\n        health = self.api_get("/health", timeout=1.0)\n    except Exception as exc:\n        try: self._last_connected = False\n        except Exception: pass\n        _tb20m_set_offline_ui(self, str(exc))\n        return\n    try: self._last_connected = bool(_tb20m_dict(health).get("ok"))\n    except Exception: self._last_connected = True\n    _tb20m_config(_tb20m_safe_getattr(self, "lbl_connection", None), text="Backend: ONLINE", text_color=("green", "light green"))\n    _tb20m_config(_tb20m_safe_getattr(self, "lbl_symbol", None), text=f"Sembol: {_tb20m_dict(health).get(\'symbol\', \'-\')}")\n    try:\n        status = self.api_get("/status", timeout=2.0)\n    except Exception as exc:\n        try: self._last_connected = True\n        except Exception: pass\n        _tb20m_config(_tb20m_safe_getattr(self, "lbl_state", None), text="Durum: STATUS ERROR")\n        _tb20m_app_set_text(self, "status_box", f"Backend online, ancak /status okunamadı.\\nReason: {exc}")\n        return\n    try: self._last_status = status\n    except Exception: pass\n    _tb20m_render_status(self, status)\n\n\ndef _tb20m_extract_training_output_path(self: _Tb20mAny, line: str) -> str | None:\n    raw = str(line or "").strip()\n    if not raw:\n        return None\n    payload = None\n    try:\n        payload = _tb20m_json.loads(raw)\n    except Exception:\n        try:\n            payload = _tb20m_ast.literal_eval(raw)\n        except Exception:\n            payload = None\n    if isinstance(payload, dict):\n        for key in ("model_path", "output_path", "output", "path", "model"):\n            value = payload.get(key)\n            if value:\n                return str(value)\n    for marker in ("model_path=", "output_path=", "output="):\n        if marker in raw:\n            return raw.split(marker, 1)[1].strip().strip("\'\\",").split()[0]\n    return None\n\n\ndef _tb20m_patch_dashboard_classes() -> None:\n    methods = {\n        "_render_logs": _tb20m_render_logs,\n        "_apply_health_aware_controls": _tb20m_apply_health_aware_controls,\n        "_api_post": _tb20m_api_post,\n        "_render_event_timeline": _tb20m_render_event_timeline,\n        "_render_session_summary": _tb20m_render_session_summary,\n        "_render_status": _tb20m_render_status,\n        "_set_offline_ui": _tb20m_set_offline_ui,\n        "_poll_health_and_status": _tb20m_poll_health_and_status,\n        "_extract_training_output_path": _tb20m_extract_training_output_path,\n    }\n    for _name, _obj in list(globals().items()):\n        if isinstance(_obj, type) and ("Dashboard" in _name or _name.endswith("App")):\n            for _m, _fn in methods.items():\n                try:\n                    setattr(_obj, _m, _fn)\n                except Exception:\n                    pass\n\n\n_tb20m_patch_dashboard_classes()\n# END 4B.4.3.6.6.20M DASHBOARD EXACT RESIDUAL FIX\n'


def patch_text(text: str) -> str:
    cleaned = re.sub(START_RE, "", text, flags=re.DOTALL)
    return cleaned.rstrip() + "\n\n" + COMPAT_BLOCK.strip() + "\n"


def patch_dashboard(root: Path) -> None:
    path = root / "src" / "tradebot" / "ui" / "dashboard.py"
    if not path.exists():
        raise RuntimeError(f"dashboard.py not found: {path}")
    path.write_text(patch_text(path.read_text(encoding="utf-8")), encoding="utf-8")


def main() -> int:
    root = Path.cwd()
    patch_dashboard(root)
    dashboard = (root / "src" / "tradebot" / "ui" / "dashboard.py").read_text(encoding="utf-8")
    checks = {
        "contract_threshold_7": ">= 7" in dashboard,
        "protective_prefixed_reason": "PROTECTIVE_EXIT_BLOCKED:" in dashboard,
        "status_contract_stale": "STATUS_CONTRACT_STALE" in dashboard,
        "pending_busy_priority": 'severity = "busy"' in dashboard,
        "audit_filter_dict_support": "Legacy tests sometimes pass a filter dictionary" in dashboard,
        "audit_summary_counts_support": "Pre-aggregated count fields" in dashboard,
        "offline_turkish_contract": "Backend çevrimdışı" in dashboard,
        "status_degrade_turkish": "Backend online, ancak /status okunamadı" in dashboard,
        "api_post_buttons_guard": "buttons = _tb20m_dict" in dashboard,
    }
    print("4B.4.3.6.6.20m dashboard exact residual fix applied")
    for key, value in checks.items():
        print(f" - {key}: {value}")
    if not all(checks.values()):
        raise RuntimeError(f"20m verification failed: {checks}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
